    }

    public static ColorValueObject FromString(string color)
    {
        return FromEnum(Enum.Parse<Color>(color));
    }

    private readonly Color _color;

    private ColorValueObject(Color color)
    {
        _color = color;
    }

    public Color Value => _color;

    public override string ToString()
    {
        return _color.ToString();
    }

    public static implicit operator Color(ColorValueObject color)
    {
        return color.Value;
    }

    public static implicit operator ColorValueObject(Color color)
    {
        return FromEnum(color);
    }

